mapper.select:
SELECT af_id, tel_id, province, city, af_address, af_aqi, af_date, af_time, af_img, af_content, af_state, gm_id, assign_date, assign_time, admin_id FROM aqi_feedback
AND (province LIKE CONCAT('%', #{keyword}, '%') OR city LIKE CONCAT('%', #{keyword}, '%') OR af_address LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY af_date DESC, af_time DESC LIMIT #{offset}, #{pageSize}

SELECT af_id, tel_id, province, city, af_address, af_aqi, af_date, af_time, af_img, af_content, af_state, gm_id, assign_date, assign_time, admin_id
FROM aqi_feedback
WHERE af_id = #{afId}

mapper.update:
UPDATE aqi_feedback
SET gm_id = #{gmId}, assign_date = #{assignDate}, assign_time = #{assignTime}, admin_id = #{adminId}, af_state = 1
WHERE af_id = #{afId}

UPDATE aqi_feedback
SET af_state = #{afState}
WHERE af_id = #{afId}
